// =========================================================
// RELATORIOS.JS
// Gera uma versão limpa e imprimível dos dados de cada aba,
// abrindo numa nova guia pronta para imprimir ou salvar como PDF
// (usando a função de impressão do próprio navegador).
// =========================================================

const LOGO_RELATORIO_BASE64 =
  "data:image/png;base64,";

// ---------------------------------------------------------
// Clona uma tabela da tela, removendo a coluna de Ações
// (botões de editar/excluir não fazem sentido no relatório)
// ---------------------------------------------------------
function clonarTabelaParaRelatorio(tbodyId) {
  const tbodyOriginal = document.getElementById(tbodyId);
  const tabelaOriginal = tbodyOriginal ? tbodyOriginal.closest("table") : null;

  if (!tabelaOriginal) {
    return "<p class='rel-vazio'>Sem dados para exibir.</p>";
  }

  const clone = tabelaOriginal.cloneNode(true);

  clone.querySelectorAll("tr").forEach((linha) => {
    const celulas = linha.querySelectorAll("th, td");
    if (celulas.length === 0) return;
    const ultima = celulas[celulas.length - 1];
    if (ultima.textContent.trim() === "Ações" || ultima.querySelector("button")) {
      ultima.remove();
    }
  });

  return clone.outerHTML;
}

// ---------------------------------------------------------
// Monta e abre o documento do relatório numa nova guia
// ---------------------------------------------------------
function abrirRelatorio(titulo, subtitulo, secoes) {
  const janela = window.open("", "_blank");

  if (!janela) {
    notificar(
      "Não foi possível abrir o relatório. Verifique se o navegador está bloqueando pop-ups para este site.",
      "erro"
    );
    return;
  }

  const agora = new Date();
  const geradoEm = agora.toLocaleString("pt-BR");

  const corpoSecoes = secoes
    .map(
      (secao) => `
        <section class="rel-secao">
          <h2>${secao.titulo}</h2>
          ${secao.tabelaHtml}
        </section>
      `
    )
    .join("");

  const html = `
    <!DOCTYPE html>
    <html lang="pt-BR">
    <head>
      <meta charset="UTF-8" />
      <title>${titulo}</title>
      <style>
        * { box-sizing: border-box; }
        body {
          font-family: -apple-system, "Segoe UI", Inter, sans-serif;
          color: #101828;
          margin: 0;
          padding: 32px 40px 60px;
          background: #fff;
        }
        .rel-cabecalho {
          display: flex;
          align-items: center;
          gap: 14px;
          border-bottom: 2px solid #1d4ed8;
          padding-bottom: 16px;
          margin-bottom: 8px;
        }
        .rel-cabecalho img {
          width: 42px;
          height: 42px;
          object-fit: cover;
          border-radius: 50%;
        }
        .rel-cabecalho h1 {
          font-size: 20px;
          margin: 0;
        }
        .rel-cabecalho p {
          margin: 2px 0 0;
          font-size: 13px;
          color: #5b6478;
        }
        .rel-meta {
          font-size: 12px;
          color: #5b6478;
          margin: 10px 0 26px;
        }
        .rel-secao {
          margin-bottom: 32px;
        }
        .rel-secao h2 {
          font-size: 15px;
          margin: 0 0 10px;
          padding-left: 10px;
          border-left: 4px solid #1d4ed8;
        }
        table {
          width: 100%;
          border-collapse: collapse;
          font-size: 12.5px;
        }
        thead th {
          text-align: left;
          background: #f1f5f9;
          border-bottom: 1px solid #cbd5e1;
          padding: 8px 10px;
          text-transform: uppercase;
          font-size: 10.5px;
          letter-spacing: 0.03em;
          color: #475569;
        }
        tbody td {
          padding: 8px 10px;
          border-bottom: 1px solid #e2e8f0;
        }
        .rel-vazio {
          font-size: 13px;
          color: #5b6478;
          font-style: italic;
        }
        .badge {
          display: inline-block;
          padding: 2px 9px;
          border-radius: 999px;
          font-size: 10.5px;
          font-weight: 700;
        }
        .badge-ok { background: #dcfce7; color: #15803d; }
        .badge-alerta { background: #fde68a; color: #b45309; }
        .badge-vencido { background: #f87171; color: #fff; }
        .badge-neutro { background: #eef1f5; color: #5b6478; }
        .linha-alerta { background: #fef3c7; }
        .linha-vencida { background: #fee2e2; }
        .linha-ok td { color: #5b6478; }
        .rel-rodape {
          margin-top: 40px;
          padding-top: 14px;
          border-top: 1px solid #e2e8f0;
          font-size: 11px;
          color: #94a3b8;
          text-align: center;
        }
        .rel-acoes-tela {
          margin: 0 0 24px;
        }
        .rel-acoes-tela button {
          padding: 9px 18px;
          border-radius: 8px;
          border: 1px solid #cbd5e1;
          background: #f8fafc;
          font-size: 13px;
          font-weight: 600;
          cursor: pointer;
        }
        @media print {
          .rel-acoes-tela { display: none; }
          body { padding: 0 24px 40px; }
        }
      </style>
    </head>
    <body>
      <div class="rel-acoes-tela">
        <button onclick="window.print()">🖨️ Imprimir / salvar como PDF</button>
      </div>

      <div class="rel-cabecalho">
        <img src="${LOGO_RELATORIO_BASE64}" alt="Logo" />
        <div>
          <h1>${titulo}</h1>
          <p>${subtitulo}</p>
        </div>
      </div>
      <div class="rel-meta">Gerado em ${geradoEm}</div>

      ${corpoSecoes}

      <div class="rel-rodape">Sistema RH — Estoque &amp; Exames · Documento gerado automaticamente</div>
    </body>
    </html>
  `;

  janela.document.open();
  janela.document.write(html);
  janela.document.close();
}

// ---------------------------------------------------------
// Relatório da aba Estoque
// ---------------------------------------------------------
function gerarRelatorioEstoque() {
  const secoes = [
    {
      titulo: "Materiais em estoque",
      tabelaHtml: clonarTabelaParaRelatorio("tabela-materiais-corpo"),
    },
    {
      titulo: "Histórico de movimentações",
      tabelaHtml: clonarTabelaParaRelatorio("tabela-historico-corpo"),
    },
  ];

  abrirRelatorio(
    "Relatório de Estoque",
    "Materiais cadastrados e histórico de movimentações",
    secoes
  );
}

