// ---------------------------------------------------------
// Relatório da aba Ausências
// ---------------------------------------------------------
function gerarRelatorioAusencias() {
  const secoes = [
    {
      titulo: "Controle de ausências",
      tabelaHtml: clonarTabelaParaRelatorio("tabela-ausencias-corpo"),
    },
  ];

  abrirRelatorio("Relatório de Ausências", "Faltas, atestados e -6h por funcionário", secoes);
}
function gerarRelatorioFuncionarios() {
  const secoes = [
    {
      titulo: "Funcionários cadastrados",
      tabelaHtml: clonarTabelaParaRelatorio("tabela-funcionarios-corpo"),
    },
    {
      titulo: "Exames periódicos e prazos",
      tabelaHtml: clonarTabelaParaRelatorio("tabela-exames-corpo"),
    },
  ];

  abrirRelatorio(
    "Relatório de Funcionários & Exames",
    "Funcionários cadastrados e situação dos exames periódicos",
    secoes
  );
}
